
WITH ids AS (
  SELECT unnest(ARRAY['973393','971511','972155','973673','974937','974928','974862','972147','971787','973214','974986','974995','975040','975021','975011','975067','975003','975137','975026','974993','971692','975030','975066','975000','971589','974992','975019','971851','971549','975023','975032','975001','971535','974296','973365','972154','972359','974295','973386','973370','973701','974919','975005','971714','972834','971676','973152','974299','972893','972559','973410','973404','954047','973436','974298','974300','973406','973368','953324','973385','974918','974484','974871','971271','971149','973500','974870','974888','973361','973362','972613','971270','974911','971168','973371','973565','972833','973354','974912','975022','975027','975042','974994','971627','975014','975056','974998','974997','975153','975007','975024','971690','975012','973888','971592','975034','975028','975068','975025','952281','952683','973366','971508','954372','973384','973581','974944','974890','972157','974343','974867','973375']) AS eid
),
ranked_ids AS (
  SELECT eid, ROW_NUMBER() OVER (ORDER BY eid) - 1 AS rn FROM ids
),
n AS (SELECT COUNT(*) AS total FROM ranked_ids),
ranked_cust AS (
  SELECT id, (ROW_NUMBER() OVER (ORDER BY id) - 1) AS rn FROM customers
)
UPDATE customers c
SET agent_employee_id = r.eid
FROM ranked_cust rc, n, ranked_ids r
WHERE c.id = rc.id
  AND r.rn = rc.rn % n.total;
